class Solution:
    def convertToBase7(self, num):
        if num == 0:
            return '0'
        neg = num < 0
        n = abs(num)
        out = ''
        while n > 0:
            out = str(n % 7) + out
            n //= 7
        return ('-' + out) if neg else out

