var convertToBase7 = function(num) {
    if (num === 0) return '0';
    const sign = num < 0 ? '-' : '';
    let n = Math.abs(num);
    let out = '';
    while (n > 0) {
        out = (n % 7) + out;
        n = Math.floor(n / 7);
    }
    return sign + out;
};
